using System;
using System.Threading;
using System.Threading.Tasks;

/// <summary>
/// Executes work with a timeout using cooperative cancellation.
/// Replaces the .NET Framework pattern of Thread.Abort, which throws
/// PlatformNotSupportedException in .NET 6+ (SYSLIB0006).
/// </summary>
public class TimedExecutor
{
    public T ExecuteWithTimeout<T>(Func<T> work, TimeSpan timeout)
    {
        // Task.Run + Task.WaitAsync gives us timeout enforcement
        // without Thread.Abort.
        var task = Task.Run(work);

        try
        {
            // Task.WaitAsync (available since .NET 6) throws
            // TimeoutException if the task doesn't complete in time.
            return task.WaitAsync(timeout).GetAwaiter().GetResult();
        }
        catch (TimeoutException)
        {
            throw new TimeoutException(
                $"Operation exceeded {timeout.TotalSeconds}s timeout");
        }
        catch (AggregateException ex) when (ex.InnerExceptions.Count == 1)
        {
            throw new AggregateException(ex.InnerException!);
        }
    }

    // Preferred: overload that accepts CancellationToken so the work
    // can cooperate with cancellation and actually stop promptly.
    public T ExecuteWithTimeout<T>(
        Func<CancellationToken, T> work, TimeSpan timeout)
    {
        using var cts = new CancellationTokenSource(timeout);

        try
        {
            var task = Task.Run(() => work(cts.Token), cts.Token);
            return task.GetAwaiter().GetResult();
        }
        catch (OperationCanceledException) when (cts.IsCancellationRequested)
        {
            throw new TimeoutException(
                $"Operation exceeded {timeout.TotalSeconds}s timeout");
        }
    }
}

